1	type Item = { type: string };
2	type Scenario = {
3	  steps: Array<{ op: string; items?: Item[] }>;
4	};
5	
6	const PROCESSING_FEE = 5;
7	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
8	  sword: 115,
9	  amulet: 71,
10	  staff: 93,
11	  potion: 49,
12	};
13	
14	export function processScenario(scenario: unknown): unknown {
15	  const { steps } = scenario as Scenario;
16	  const results = steps.map((step) => {
17	    const items = step.items ?? [];
18	    if (items.length === 0) return { premium: PROCESSING_FEE };
19	    return { premium: PREMIUM_BY_ITEM_TYPE[items[0].type] };
20	  });
21	  return { results };
22	}
